func anyStr(m map[string]any, k string) string {
	if v, ok := m[k]; ok && v != nil {
		switch x := v.(type) {
		case string:
			return x
		case float64:
			if x == float64(int64(x)) {
				return intStr(int(x))
			}
			return floatStr(x)
		case bool:
			if x {
				return "1"
			}
			return ""
		}
	}
	return ""
}

